import{_ as e,c as a,o,ag as i}from"./chunks/framework.DD2hp6gW.js";const p=JSON.parse('{"title":"Frontend Display","description":"","frontmatter":{},"headers":[],"relativePath":"frontend-display.md","filePath":"frontend-display.md","lastUpdated":1777110900000}'),n={name:"frontend-display.md"};function s(r,t,l,d,h,c){return o(),a("div",null,t[0]||(t[0]=[i('<h1 id="frontend-display" tabindex="-1">Frontend Display <a class="header-anchor" href="#frontend-display" aria-label="Permalink to &quot;Frontend Display&quot;">​</a></h1><p>OptionBay is designed to provide a seamless and interactive experience for your customers directly on the product page. This section explains how the options are rendered, how they interact with the WooCommerce interface, and how you can customize their appearance.</p><h2 id="option-placement" tabindex="-1">Option Placement <a class="header-anchor" href="#option-placement" aria-label="Permalink to &quot;Option Placement&quot;">​</a></h2><p>By default, OptionBay hooks into the <code>woocommerce_before_add_to_cart_button</code> action. This ensures that your custom options appear right before the &quot;Add to Cart&quot; button, which is the most natural position for product customizations.</p><ul><li><strong>Responsive Design:</strong> All field types are fully responsive and will adapt to the width of your theme&#39;s product container.</li><li><strong>Orientation:</strong> You can choose between <strong>Vertical</strong> (stacked) and <strong>Horizontal</strong> (side-by-side) layouts for radio and checkbox groups in the <a href="./settings.html">Global Settings</a>.</li></ul><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>If your theme uses a custom product template that does not fire the standard <code>woocommerce_before_add_to_cart_button</code> hook, OptionBay fields may not appear automatically. Contact your theme developer or use a manual template override to add the hook.</p></div><h2 id="interactive-features" tabindex="-1">Interactive Features <a class="header-anchor" href="#interactive-features" aria-label="Permalink to &quot;Interactive Features&quot;">​</a></h2><h3 id="live-price-updates" tabindex="-1">Live Price Updates <a class="header-anchor" href="#live-price-updates" aria-label="Permalink to &quot;Live Price Updates&quot;">​</a></h3><p>One of the core features of OptionBay is the live total display. As customers select options or type into fields:</p><ul><li>The price deltas are calculated instantly using JavaScript on the client side.</li><li>An <strong>Option Total</strong> display appears near the Add to Cart button showing the real-time cost of all selected addons.</li><li>The combined total (base price + addon prices) updates dynamically so customers always know the final cost before adding to cart.</li></ul><h3 id="instant-conditional-logic" tabindex="-1">Instant Conditional Logic <a class="header-anchor" href="#instant-conditional-logic" aria-label="Permalink to &quot;Instant Conditional Logic&quot;">​</a></h3><p>Fields with <a href="./conditional-logic.html">Conditional Logic</a> will show or hide instantly based on user input. There is no page reload — the transitions happen smoothly in real time. This keeps the form clean by only showing relevant fields, creating a personalized shopping journey.</p><h3 id="real-time-validation" tabindex="-1">Real-time Validation <a class="header-anchor" href="#real-time-validation" aria-label="Permalink to &quot;Real-time Validation&quot;">​</a></h3><ul><li><strong>Required Fields:</strong> If a required field is empty, the &quot;Add to Cart&quot; button will be disabled. A red asterisk (*) appears next to required field labels, and a notice will appear if the user tries to submit without completing them.</li><li><strong>Number Constraints:</strong> Number fields enforce min/max/step constraints via the native browser controls.</li><li><strong>File Types:</strong> File upload fields validate the file extension and size on the client side before the upload begins, and again on the server side for security.</li></ul><h2 id="field-styling" tabindex="-1">Field Styling <a class="header-anchor" href="#field-styling" aria-label="Permalink to &quot;Field Styling&quot;">​</a></h2><p>OptionBay uses clean, semantic HTML that inherits as much styling as possible from your active WordPress theme. This ensures a consistent look and feel across your store.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Element</th><th style="text-align:left;">Behavior</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Labels</strong></td><td style="text-align:left;">Inherit your theme&#39;s label or paragraph styles. Font size is configurable in <a href="./settings.html">Global Settings</a>.</td></tr><tr><td style="text-align:left;"><strong>Inputs</strong></td><td style="text-align:left;">Dropdowns, text fields, and number inputs match your theme&#39;s default input styling. Font size is configurable.</td></tr><tr><td style="text-align:left;"><strong>Radio &amp; Checkboxes</strong></td><td style="text-align:left;">Use native browser rendering, styled by your theme.</td></tr><tr><td style="text-align:left;"><strong>Color Swatches</strong></td><td style="text-align:left;">Rendered as colored blocks with configurable size and border-radius via <a href="./settings.html">Global Settings</a>.</td></tr><tr><td style="text-align:left;"><strong>Image Swatches</strong></td><td style="text-align:left;">Rendered as thumbnail images with configurable size and border-radius via <a href="./settings.html">Global Settings</a>.</td></tr><tr><td style="text-align:left;"><strong>Descriptions</strong></td><td style="text-align:left;">Shown as small helper text below each field.</td></tr></tbody></table><h2 id="customization" tabindex="-1">Customization <a class="header-anchor" href="#customization" aria-label="Permalink to &quot;Customization&quot;">​</a></h2><p>If you need to further customize the look of your options, you can add custom CSS to your theme&#39;s stylesheet targeting the OptionBay field containers. The HTML structure uses semantic class names prefixed with <code>optionbay-</code> for easy targeting.</p><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li><a href="./cart-checkout.html">Learn about Cart &amp; Checkout Integration</a></li><li><a href="./settings.html">Configure Global Settings</a></li></ul>',21)]))}const f=e(n,[["render",s]]);export{p as __pageData,f as default};
